                Apex<span className="text-purple-600">Connect</span>
              </a>
            </motion.div>
            <div className="hidden md:block">
              <div className="ml-10 flex items-baseline space-x-6">
                {navLinks.map((link) => (
                  <a
                    key={link.name}
                    href={link.href}
                    className="text-slate-700 hover:text-indigo-600 px-3 py-2 rounded-md text-base font-medium transition duration-300 ease-in-out"
